#include <stdio.h>
int minFallingPathSum(int** triangle, int triangleSize, int* triangleColSize) {
    int n = triangleSize;
    int dp[n][n];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            dp[i][j] = -1;
        }
    }
    return helper(triangle, dp, 0, 0, n);
}

int helper(int** triangle, int** dp, int i, int j, int n) {
    if (i == n - 1) return triangle[i][j];
    if (dp[i][j] != -1) return dp[i][j];
    int down = triangle[i][j] + helper(triangle, dp, i + 1, j, n);
    int diag = triangle[i][j] + helper(triangle, dp, i + 1, j + 1, n);
    return dp[i][j] = (down < diag) ? down : diag;
}

