class Solution {
    // Recursive function with memoization
    solve(i, j, triangle, n, dp) {
        // If value already computed
        if (dp[i][j] !== -1)
            return dp[i][j];

        // If at bottom row
        if (i === n - 1)
            return triangle[i][j];

        // Compute both downward and diagonal moves
        let down = triangle[i][j] + this.solve(i + 1, j, triangle, n, dp);
        let diag = triangle[i][j] + this.solve(i + 1, j + 1, triangle, n, dp);

        // Store and return min path sum
        dp[i][j] = Math.min(down, diag);
        return dp[i][j];
    }

    // Function to start the process
    minimumPathSum(triangle) {
        let n = triangle.length;
        let dp = Array.from({ length: n }, () => Array(n).fill(-1));
        return this.solve(0, 0, triangle, n, dp);
    }
}

